//Scripted pipeline
node {
    stage('Ejemplo') {
        try {
            sh 'exit 1'
        }
        catch (exc) {
            echo 'Oh dios, se prende fuego Jenkins!!'
            throw e
        }
    }
}
//Declarative pipeline
pipeline {
        agent any

    tools {
        nodejs "NodeJS"
    }

    stages {
        stage('Deploy de la app a Testing') {
            steps {
                echo 'Se buildeo la app'
                echo 'Otras acciones que pueden pasar en este Stage'
            }
        }

        stage('Ejecución de Unit Tests') {
            steps {
                echo 'Se ejecutan los Unit Tests'
                echo 'Se crea el reporte'
            }
        }

        stage('Ejecución de E2E Tests') {
            steps {
                echo 'Se ejecutan los E2E Tests'

                // Este comando hace que la etapa falle inmediatamente
                error "Simulación de fallo: Los tests E2E encontraron un error crítico."

                echo 'Se crea el reporte'
            }
        }

        stage('Deploy a Prod') {
            steps {
                echo 'Se empaquetan los artefactos'
                echo 'Se hace el deploy final'
            }
        }
    }
} // <-- Esta es la llave de
